export const TOTAL_DAYS = 364;

// Each calendar day in the plan carries exactly one reading: the weekday
// fixes the track (Sunday is always Epistles, Monday always The Law, ...)
// and the week number picks how far along that track you are.
export function getReadingForDay(dayNumber: number): ReadingEntry | undefined {
  return READING_PLAN.find((e) => e.dayNumber === dayNumber);
}
